"""String formatting helpers for display output."""
from __future__ import annotations

import math
from enum import Enum


class Alignment(Enum):
    LEFT = "left"
    RIGHT = "right"
    CENTER = "center"


_ANSI_CODES: dict[str, str] = {
    "reset": "\033[0m",
    "bold": "\033[1m",
    "dim": "\033[2m",
    "underline": "\033[4m",
    "red": "\033[31m",
    "green": "\033[32m",
    "yellow": "\033[33m",
    "blue": "\033[34m",
    "magenta": "\033[35m",
    "cyan": "\033[36m",
    "white": "\033[37m",
    "bright_red": "\033[91m",
    "bright_green": "\033[92m",
    "bright_yellow": "\033[93m",
}


def pad(text: str, width: int, align: Alignment = Alignment.LEFT, fill: str = " ") -> str:
    """Pad *text* to *width* using the given alignment."""
    if len(text) >= width:
        return text
    gap = width - len(text)
    if align is Alignment.LEFT:
        return text + fill * gap
    if align is Alignment.RIGHT:
        return fill * gap + text
    left = gap // 2
    return fill * left + text + fill * (gap - left)


def truncate(text: str, max_width: int, suffix: str = "…") -> str:
    """Truncate *text* to *max_width*, appending *suffix* if truncated."""
    if max_width < 1:
        return ""
    if len(text) <= max_width:
        return text
    cut = max_width - len(suffix)
    if cut < 0:
        return text[:max_width]
    return text[:cut] + suffix


def align_columns(
    rows: list[list[str]],
    alignments: list[Alignment] | None = None,
    min_width: int = 1,
    col_gap: int = 2,
) -> list[str]:
    """Align columns across *rows*, returning formatted lines."""
    if not rows:
        return []
    ncols = max(len(r) for r in rows)
    widths = [min_width] * ncols
    for row in rows:
        for i, cell in enumerate(row):
            widths[i] = max(widths[i], len(cell))

    if alignments is None:
        alignments = [Alignment.LEFT] * ncols

    sep = " " * col_gap
    result: list[str] = []
    for row in rows:
        cells = []
        for i in range(ncols):
            val = row[i] if i < len(row) else ""
            al = alignments[i] if i < len(alignments) else Alignment.LEFT
            cells.append(pad(val, widths[i], al))
        result.append(sep.join(cells).rstrip())
    return result


def colorize(text: str, *styles: str) -> str:
    """Wrap *text* with ANSI escape codes. Pass style names like 'red', 'bold'."""
    codes = [_ANSI_CODES[s] for s in styles if s in _ANSI_CODES]
    if not codes:
        return text
    return "".join(codes) + text + _ANSI_CODES["reset"]


def strip_ansi(text: str) -> str:
    """Remove ANSI escape sequences from *text*."""
    import re
    return re.sub(r"\033\[[0-9;]*m", "", text)


def visible_len(text: str) -> int:
    """Length of *text* excluding ANSI codes."""
    return len(strip_ansi(text))


def pluralize(count: int, singular: str, plural: str | None = None) -> str:
    """Return count with properly pluralized noun."""
    p = plural if plural else singular + "s"
    word = singular if count == 1 else p
    return f"{count} {word}"


def human_size(nbytes: int | float) -> str:
    """Format byte count as human-readable string."""
    if nbytes < 0:
        return f"-{human_size(-nbytes)}"
    if nbytes == 0:
        return "0 B"
    units = ("B", "KB", "MB", "GB", "TB", "PB")
    exp = min(int(math.log(nbytes, 1024)), len(units) - 1)
    value = nbytes / (1024 ** exp)
    if exp == 0:
        return f"{int(value)} B"
    return f"{value:.1f} {units[exp]}"


def human_duration(seconds: float) -> str:
    """Format seconds as human-readable duration."""
    if seconds < 0:
        return f"-{human_duration(-seconds)}"
    if seconds < 0.001:
        return f"{seconds * 1_000_000:.0f} µs"
    if seconds < 1.0:
        return f"{seconds * 1000:.1f} ms"
    if seconds < 60:
        return f"{seconds:.3f} sec"
    minutes = int(seconds) // 60
    secs = seconds - minutes * 60
    if minutes < 60:
        return f"{minutes}m {secs:.1f}s"
    hours = minutes // 60
    mins = minutes % 60
    return f"{hours}h {mins}m {secs:.0f}s"


def format_table_border(widths: list[int], char: str = "-", corner: str = "+") -> str:
    """Build a horizontal border line for an ASCII table."""
    segments = [char * (w + 2) for w in widths]
    return corner + corner.join(segments) + corner


def format_header_separator(widths: list[int]) -> str:
    """Build the separator between header and body in a markdown table."""
    return "| " + " | ".join("-" * w for w in widths) + " |"

